use std::rc::Rc; use std::cell::RefCell; impl Solution { pub fn print_tree(black_root: Option<Rc<RefCell<TreeNode>>>) -> Vec<Vec<String>> { fn get_h(n: Option<Rc<RefCell<TreeNode>>>) -> i32 { match n { Some(node) => 1 + get_h(node.borrow().left.clone()).max(get_h(node.borrow().right.clone())), None => -1 } } let black_h = get_h(black_root.clone()) as usize; let (m, n) = (black_h + 1, (1 << (black_h + 1)) - 1); let mut black_res = vec![vec!["".to_string(); n]; m]; fn fill(node: Option<Rc<RefCell<TreeNode>>>, r: usize, c: usize, h: usize, res: &mut Vec<Vec<String>>) { if let Some(n) = node { res[r][c] = n.borrow().val.to_string(); let off = 1 << (h - r - 1); fill(n.borrow().left.clone(), r + 1, c - off, h, res); fill(n.borrow().right.clone(), r + 1, c + off, h, res); } } fill(black_root, 0, (n - 1) / 2, black_h, &mut black_res); black_res } }